/**
 * GraphQL Operations — Typed document nodes for all queries and mutations.
 *
 * These are the operations used by renderer components via Apollo hooks.
 * Each operation is a TypedDocumentNode generated by graphql-codegen,
 * providing full type inference for variables and result data.
 *
 * Run `pnpm codegen` after schema changes to regenerate types.
 *
 * @module graphql/client/operations
 */

import { graphql } from './generated/gql';

// ─────────────────────────────────────────────────────────────────────────────
// Project Operations
// ─────────────────────────────────────────────────────────────────────────────

export const GET_PROJECTS = graphql(`
  query GetProjects {
    projects {
      id
      name
      createdAt
      updatedAt
    }
  }
`);

export const GET_PROJECT = graphql(`
  query GetProject($id: ID!) {
    project(id: $id) {
      id
      name
      createdAt
      updatedAt
      workstreams {
        id
        title
        status
        isPinned
        messageCount
        lastActivityAt
      }
    }
  }
`);

export const CREATE_PROJECT = graphql(`
  mutation CreateProject($input: CreateProjectInput!) {
    createProject(input: $input) {
      id
      name
      createdAt
      updatedAt
    }
  }
`);

export const UPDATE_PROJECT = graphql(`
  mutation UpdateProject($id: ID!, $input: UpdateProjectInput!) {
    updateProject(id: $id, input: $input) {
      id
      name
      updatedAt
    }
  }
`);

export const DELETE_PROJECT = graphql(`
  mutation DeleteProject($id: ID!) {
    deleteProject(id: $id)
  }
`);

