/**
 * Fetch user-sent message history for a workstream (newest first).
 *
 * Used to populate the chat input's up-arrow message history.
 * Supports cursor-based pagination via the `before` argument
 * for preemptive loading as the user navigates backward.
 */
export const GET_USER_MESSAGE_HISTORY = graphql(`
  query GetUserMessageHistory($workstreamId: ID!, $limit: Int, $before: Int) {
    userMessageHistory(workstreamId: $workstreamId, limit: $limit, before: $before) {
      items {
        eventId
        messageId
        text
        timestamp
      }
      hasMore
    }
  }
`);

