export const GET_ENTITY_TOOL_ENTRIES = graphql(`
  query GetEntityToolEntries {
    entityToolEntries {
      uri
      addedAt
    }
  }
`);

export const ADD_ENTITY_TOOL_ENTRY = graphql(`
  mutation AddEntityToolEntry($uri: String!) {
    addEntityToolEntry(uri: $uri) {
      entry {
        uri
        addedAt
      }
      alreadyExists
    }
  }
`);

export const REMOVE_ENTITY_TOOL_ENTRY = graphql(`
  mutation RemoveEntityToolEntry($uri: String!) {
    removeEntityToolEntry(uri: $uri) {
      success
    }
  }
`);
